/**
 * Email notification adapter.
 *
 * Implements NotificationAdapter for the email channel with:
 * - Template rendering per notification type (HTML + plain text)
 * - Recipient validation
 * - Pluggable transport (inject any send function — SES, SendGrid, SMTP, etc.)
 * - In-memory fallback transport for development/testing
 */

import type { NotificationAdapter } from './notification.adapter.js';
import type {
  NotificationChannel,
  NotificationPayload,
  NotificationType,
  NotificationResult,
} from '../models/notification.js';
import { Logger } from '../utils/logger.js';

/** Structure representing a rendered email ready for delivery. */
export interface RenderedEmail {
  to: string;
  subject: string;
  html: string;
  text: string;
}

/** Transport function signature — adapts to any email provider. */
export type EmailTransport = (email: RenderedEmail) => Promise<{ messageId: string }>;

/** Record of a sent email, stored in-memory for inspection. */
export interface SentEmailRecord {
  payload: NotificationPayload;
  rendered: RenderedEmail;
  messageId: string;
  timestamp: Date;
}

/** Configuration for the email adapter. */
export interface EmailAdapterConfig {
  /** From address for outgoing emails. */
  fromAddress: string;
  /** Optional custom transport. Falls back to in-memory transport if omitted. */
  transport?: EmailTransport;
}

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Render an HTML email body from a notification payload.
 * Each notification type gets its own template structure.
 */
function renderHtml(payload: NotificationPayload): string {
  const header = `<h1 style="color:#333;font-family:sans-serif;">${escapeHtml(payload.subject)}</h1>`;
  const body = templateBodyHtml(payload.type, payload.body, payload.metadata);
  return `<!DOCTYPE html><html><head><meta charset="utf-8"></head><body style="margin:0;padding:20px;background:#f9f9f9;">${header}${body}</body></html>`;
}

function templateBodyHtml(
  type: NotificationType,
  body: string,
  metadata?: Record<string, unknown>,
): string {
  const escapedBody = escapeHtml(body);

  switch (type) {
    case 'order_confirmation': {
      const orderId = metadata?.orderId ? escapeHtml(String(metadata.orderId)) : '';
      return `<div style="padding:16px;background:#fff;border:1px solid #e0e0e0;border-radius:4px;"><p>${escapedBody}</p>${orderId ? `<p style="color:#666;font-size:12px;">Order ID: ${orderId}</p>` : ''}</div>`;
    }
    case 'order_status_update': {
      const prev = metadata?.previousStatus ? escapeHtml(String(metadata.previousStatus)) : '';
      const next = metadata?.newStatus ? escapeHtml(String(metadata.newStatus)) : '';
      return `<div style="padding:16px;background:#fff;border:1px solid #e0e0e0;border-radius:4px;"><p>${escapedBody}</p>${prev && next ? `<p><strong>${prev}</strong> &rarr; <strong>${next}</strong></p>` : ''}</div>`;
    }
    case 'welcome':
      return `<div style="padding:16px;background:#e8f5e9;border-radius:4px;"><p>${escapedBody}</p><p>Get started by exploring your dashboard.</p></div>`;
    case 'account_updated':
      return `<div style="padding:16px;background:#fff3e0;border-radius:4px;"><p>${escapedBody}</p></div>`;
    default:
      return `<div style="padding:16px;"><p>${escapedBody}</p></div>`;
  }
}

function escapeHtml(str: string): string {
  return str
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;');
}

/** Render a plain-text fallback from the payload. */
function renderText(payload: NotificationPayload): string {
  return `${payload.subject}\n\n${payload.body}`;
}

/** Validate that a recipient looks like an email address. */
function isValidEmail(recipient: string): boolean {
  return EMAIL_REGEX.test(recipient);
}

/** Default in-memory transport for development and testing. */
function createInMemoryTransport(): EmailTransport {
  let counter = 0;
  return async () => ({ messageId: `mem-${Date.now()}-${++counter}` });
}

export class EmailNotificationAdapter implements NotificationAdapter {
  readonly channel: NotificationChannel = 'email';
  private logger = new Logger('EmailAdapter');
  private sent: SentEmailRecord[] = [];
  private transport: EmailTransport;
  private fromAddress: string;

  constructor(config?: Partial<EmailAdapterConfig>) {
    this.fromAddress = config?.fromAddress ?? 'noreply@taskflow.example.com';
    this.transport = config?.transport ?? createInMemoryTransport();
  }

  async send(payload: NotificationPayload): Promise<NotificationResult> {
    if (!isValidEmail(payload.recipient)) {
      this.logger.warn(`Invalid email recipient: ${payload.recipient}`);
      return {
        success: false,
        channel: this.channel,
        recipient: payload.recipient,
        error: `Invalid email address: ${payload.recipient}`,
      };
    }

    const rendered: RenderedEmail = {
      to: payload.recipient,
      subject: payload.subject,
      html: renderHtml(payload),
      text: renderText(payload),
    };

    try {
      const { messageId } = await this.transport(rendered);

      this.logger.info(`Email sent to ${payload.recipient}: ${payload.subject} [${messageId}]`);
      this.sent.push({ payload, rendered, messageId, timestamp: new Date() });

      return {
        success: true,
        channel: this.channel,
        recipient: payload.recipient,
        messageId,
      };
    } catch (err) {
      const errorMessage = err instanceof Error ? err.message : String(err);
      this.logger.error(`Failed to send email to ${payload.recipient}: ${errorMessage}`);

      return {
        success: false,
        channel: this.channel,
        recipient: payload.recipient,
        error: errorMessage,
      };
    }
  }

  /** Get all sent email records. */
  getSentEmails(): SentEmailRecord[] {
    return [...this.sent];
  }

  /** Clear sent email records. */
  clearSentEmails(): void {
    this.sent = [];
  }

  /** Get the configured from address. */
  getFromAddress(): string {
    return this.fromAddress;
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import {
  EmailNotificationAdapter,
  type EmailTransport,
  type RenderedEmail,
} from '../../src/adapters/email.adapter.js';
import type { NotificationPayload } from '../../src/models/notification.js';

function makePayload(overrides?: Partial<NotificationPayload>): NotificationPayload {
  return {
    type: 'order_confirmation',
    recipient: 'alice@example.com',
    subject: 'Order Confirmation: ord-001',
    body: 'Your order has been placed. Items: Widget x2. Total: $25.00',
    metadata: { orderId: 'ord-001', userId: 'user-001' },
    ...overrides,
  };
}

describe('EmailNotificationAdapter', () => {
  let adapter: EmailNotificationAdapter;

  beforeEach(() => {
    adapter = new EmailNotificationAdapter();
  });

  describe('channel', () => {
    it('should report email channel', () => {
      expect(adapter.channel).toBe('email');
    });
  });

  describe('configuration', () => {
    it('should use default from address', () => {
      expect(adapter.getFromAddress()).toBe('noreply@taskflow.example.com');
    });

    it('should accept custom from address', () => {
      const custom = new EmailNotificationAdapter({ fromAddress: 'support@acme.com' });
      expect(custom.getFromAddress()).toBe('support@acme.com');
    });

    it('should accept custom transport', async () => {
      const transport: EmailTransport = async () => ({ messageId: 'custom-123' });
      const custom = new EmailNotificationAdapter({ transport });
      const result = await custom.send(makePayload());
      expect(result.messageId).toBe('custom-123');
    });
  });

  describe('recipient validation', () => {
    it('should reject empty recipient', async () => {
      const result = await adapter.send(makePayload({ recipient: '' }));
      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email address');
    });

    it('should reject recipient without @', async () => {
      const result = await adapter.send(makePayload({ recipient: 'not-an-email' }));
      expect(result.success).toBe(false);
      expect(result.error).toContain('Invalid email address');
    });

    it('should reject recipient without domain', async () => {
      const result = await adapter.send(makePayload({ recipient: 'user@' }));
      expect(result.success).toBe(false);
    });

    it('should accept valid email', async () => {
      const result = await adapter.send(makePayload({ recipient: 'user@domain.com' }));
      expect(result.success).toBe(true);
    });
  });

  describe('template rendering', () => {
    let captured: RenderedEmail[];
    let renderAdapter: EmailNotificationAdapter;

    beforeEach(() => {
      captured = [];
      const transport: EmailTransport = async (email) => {
        captured.push(email);
        return { messageId: 'test-msg' };
      };
      renderAdapter = new EmailNotificationAdapter({ transport });
    });

    it('should render order_confirmation with order ID in HTML', async () => {
      await renderAdapter.send(makePayload());
      expect(captured).toHaveLength(1);
      expect(captured[0]!.html).toContain('Order ID: ord-001');
      expect(captured[0]!.html).toContain('<!DOCTYPE html>');
    });

    it('should render order_status_update with status transition', async () => {
      await renderAdapter.send(
        makePayload({
          type: 'order_status_update',
          subject: 'Order Update: ord-002',
          body: 'Your order status has changed from pending to shipped.',
          metadata: { orderId: 'ord-002', previousStatus: 'pending', newStatus: 'shipped' },
        }),
      );
      expect(captured[0]!.html).toContain('pending');
      expect(captured[0]!.html).toContain('shipped');
      expect(captured[0]!.html).toContain('&rarr;');
    });

    it('should render welcome template', async () => {
      await renderAdapter.send(
        makePayload({
          type: 'welcome',
          subject: 'Welcome to TaskFlow Pro',
          body: 'Welcome, Alice! Your account has been created.',
        }),
      );
      expect(captured[0]!.html).toContain('Get started by exploring your dashboard');
      expect(captured[0]!.html).toContain('background:#e8f5e9');
    });

    it('should render account_updated template', async () => {
      await renderAdapter.send(
        makePayload({
          type: 'account_updated',
          subject: 'Account Updated',
          body: 'Your account has been updated. Changed fields: email.',
        }),
      );
      expect(captured[0]!.html).toContain('background:#fff3e0');
    });

    it('should produce plain-text fallback', async () => {
      await renderAdapter.send(makePayload());
      expect(captured[0]!.text).toBe(
        'Order Confirmation: ord-001\n\nYour order has been placed. Items: Widget x2. Total: $25.00',
      );
    });

    it('should escape HTML entities in body', async () => {
      await renderAdapter.send(
        makePayload({ body: 'Total: <script>alert("xss")</script>' }),
      );
      expect(captured[0]!.html).not.toContain('<script>');
      expect(captured[0]!.html).toContain('&lt;script&gt;');
    });
  });

  describe('send success', () => {
    it('should return success result with messageId', async () => {
      const result = await adapter.send(makePayload());
      expect(result.success).toBe(true);
      expect(result.channel).toBe('email');
      expect(result.recipient).toBe('alice@example.com');
      expect(result.messageId).toBeDefined();
    });

    it('should track sent emails', async () => {
      await adapter.send(makePayload());
      await adapter.send(makePayload({ recipient: 'bob@example.com' }));
      const sent = adapter.getSentEmails();
      expect(sent).toHaveLength(2);
      expect(sent[0]!.payload.recipient).toBe('alice@example.com');
      expect(sent[1]!.payload.recipient).toBe('bob@example.com');
    });

    it('should store rendered email in sent records', async () => {
      await adapter.send(makePayload());
      const sent = adapter.getSentEmails();
      expect(sent[0]!.rendered.html).toContain('<!DOCTYPE html>');
      expect(sent[0]!.rendered.to).toBe('alice@example.com');
    });
  });

  describe('transport failure', () => {
    it('should return failure result when transport throws', async () => {
      const failing: EmailTransport = async () => {
        throw new Error('SMTP connection refused');
      };
      const failAdapter = new EmailNotificationAdapter({ transport: failing });
      const result = await failAdapter.send(makePayload());
      expect(result.success).toBe(false);
      expect(result.error).toBe('SMTP connection refused');
      expect(result.channel).toBe('email');
    });

    it('should not record failed sends in sent list', async () => {
      const failing: EmailTransport = async () => {
        throw new Error('timeout');
      };
      const failAdapter = new EmailNotificationAdapter({ transport: failing });
      await failAdapter.send(makePayload());
      expect(failAdapter.getSentEmails()).toHaveLength(0);
    });
  });

  describe('clearSentEmails', () => {
    it('should clear sent records', async () => {
      await adapter.send(makePayload());
      expect(adapter.getSentEmails()).toHaveLength(1);
      adapter.clearSentEmails();
      expect(adapter.getSentEmails()).toHaveLength(0);
    });
  });
});

