+
+  beforeEach(() => {
+    adapter = new EmailNotificationAdapter();
+  });
+
+  describe('channel', () => {
+    it('should report email channel', () => {
+      expect(adapter.channel).toBe('email');
+    });
+  });
+
+  describe('configuration', () => {
+    it('should use default from address', () => {
+      expect(adapter.getFromAddress()).toBe('noreply@taskflow.example.com');
+    });
+
+    it('should accept custom from address', () => {
+      const custom = new EmailNotificationAdapter({ fromAddress: 'support@acme.com' });
+      expect(custom.getFromAddress()).toBe('support@acme.com');
+    });
+
+    it('should accept custom transport', async () => {
+      const transport: EmailTransport = async () => ({ messageId: 'custom-123' });
+      const custom = new EmailNotificationAdapter({ transport });
+      const result = await custom.send(makePayload());
+      expect(result.messageId).toBe('custom-123');
+    });
+  });
+
+  describe('recipient validation', () => {
+    it('should reject empty recipient', async () => {
+      const result = await adapter.send(makePayload({ recipient: '' }));
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Invalid email address');
+    });
+
+    it('should reject recipient without @', async () => {
+      const result = await adapter.send(makePayload({ recipient: 'not-an-email' }));
+      expect(result.success).toBe(false);
+      expect(result.error).toContain('Invalid email address');
+    });
+
+    it('should reject recipient without domain', async () => {
+      const result = await adapter.send(makePayload({ recipient: 'user@' }));
+      expect(result.success).toBe(false);
+    });
+
+    it('should accept valid email', async () => {
+      const result = await adapter.send(makePayload({ recipient: 'user@domain.com' }));
+      expect(result.success).toBe(true);
+    });
+  });
+
+  describe('template rendering', () => {
+    let captured: RenderedEmail[];
+    let renderAdapter: EmailNotificationAdapter;
+
+    beforeEach(() => {
+      captured = [];
+      const transport: EmailTransport = async (email) => {
+        captured.push(email);
+        return { messageId: 'test-msg' };
+      };
+      renderAdapter = new EmailNotificationAdapter({ transport });
+    });
+
+    it('should render order_confirmation with order ID in HTML', async () => {
+      await renderAdapter.send(makePayload());
+      expect(captured).toHaveLength(1);
+      expect(captured[0]!.html).toContain('Order ID: ord-001');
+      expect(captured[0]!.html).toContain('<!DOCTYPE html>');
+    });
+
+    it('should render order_status_update with status transition', async () => {
+      await renderAdapter.send(
+        makePayload({
+          type: 'order_status_update',
+          subject: 'Order Update: ord-002',
+          body: 'Your order status has changed from pending to shipped.',
+          metadata: { orderId: 'ord-002', previousStatus: 'pending', newStatus: 'shipped' },
+        }),
+      );
+      expect(captured[0]!.html).toContain('pending');
+      expect(captured[0]!.html).toContain('shipped');
+      expect(captured[0]!.html).toContain('&rarr;');
+    });
+
+    it('should render welcome template', async () => {
+      await renderAdapter.send(
+        makePayload({
+          type: 'welcome',
+          subject: 'Welcome to TaskFlow Pro',
+          body: 'Welcome, Alice! Your account has been created.',
+        }),
+      );
+      expect(captured[0]!.html).toContain('Get started by exploring your dashboard');
+      expect(captured[0]!.html).toContain('background:#e8f5e9');
+    });
+
+    it('should render account_updated template', async () => {
+      await renderAdapter.send(
+        makePayload({
+          type: 'account_updated',
+          subject: 'Account Updated',
+          body: 'Your account has been updated. Changed fields: email.',
+        }),
+      );
+      expect(captured[0]!.html).toContain('background:#fff3e0');
+    });
+
+    it('should produce plain-text fallback', async () => {
+      await renderAdapter.send(makePayload());
+      expect(captured[0]!.text).toBe(
+        'Order Confirmation: ord-001\n\nYour order has been placed. Items: Widget x2. Total: $25.00',
+      );
+    });
+
+    it('should escape HTML entities in body', async () => {
+      await renderAdapter.send(
+        makePayload({ body: 'Total: <script>alert("xss")</script>' }),
+      );
+      expect(captured[0]!.html).not.toContain('<script>');
+      expect(captured[0]!.html).toContain('&lt;script&gt;');
+    });
+  });
+
+  describe('send success', () => {
+    it('should return success result with messageId', async () => {
+      const result = await adapter.send(makePayload());
+      expect(result.success).toBe(true);
+      expect(result.channel).toBe('email');
+      expect(result.recipient).toBe('alice@example.com');
+      expect(result.messageId).toBeDefined();
+    });
+
+    it('should track sent emails', async () => {
+      await adapter.send(makePayload());
+      await adapter.send(makePayload({ recipient: 'bob@example.com' }));
+      const sent = adapter.getSentEmails();
+      expect(sent).toHaveLength(2);
+      expect(sent[0]!.payload.recipient).toBe('alice@example.com');
+      expect(sent[1]!.payload.recipient).toBe('bob@example.com');
+    });
+
+    it('should store rendered email in sent records', async () => {
+      await adapter.send(makePayload());
+      const sent = adapter.getSentEmails();
+      expect(sent[0]!.rendered.html).toContain('<!DOCTYPE html>');
+      expect(sent[0]!.rendered.to).toBe('alice@example.com');
+    });
+  });
+
+  describe('transport failure', () => {
+    it('should return failure result when transport throws', async () => {
+      const failing: EmailTransport = async () => {
+        throw new Error('SMTP connection refused');
+      };
+      const failAdapter = new EmailNotificationAdapter({ transport: failing });
+      const result = await failAdapter.send(makePayload());
+      expect(result.success).toBe(false);
+      expect(result.error).toBe('SMTP connection refused');
+      expect(result.channel).toBe('email');
+    });
+
+    it('should not record failed sends in sent list', async () => {
+      const failing: EmailTransport = async () => {
+        throw new Error('timeout');
+      };
+      const failAdapter = new EmailNotificationAdapter({ transport: failing });
+      await failAdapter.send(makePayload());
+      expect(failAdapter.getSentEmails()).toHaveLength(0);
+    });
+  });
+
+  describe('clearSentEmails', () => {
+    it('should clear sent records', async () => {
+      await adapter.send(makePayload());
+      expect(adapter.getSentEmails()).toHaveLength(1);
+      adapter.clearSentEmails();
+      expect(adapter.getSentEmails()).toHaveLength(0);
+    });
+  });
+});

